\begin{table}[!t]
  \centering
  \small
  \caption{Corruption results across slices and models. ``QO'' = question-only
  (no chain). Bold = largest accuracy drop from baseline.
  The positional sensitivity reverses completely with chain format:
  Hard-v3 (no answer-bearing suffix) is prefix-sensitive;
  GSM8K-v1 (explicit answer in suffix) is suffix-sensitive.
  The within-dataset format ablation (Table~\ref{tab:ablation}) isolates the
  mechanism; this table shows the cross-format reversal.}
  \label{tab:main-results}
  \begin{tabular}{llccccc}
    \toprule
    Slice & Model & Baseline & Middle & Prefix & Suffix & QO \\
    \midrule
    \multirow{2}{*}{Hard-v3 ($N{=}60$)}
      & Qwen~2.5-3B  & 0.183 & 0.050 & \textbf{0.017} & 0.267 & 0.083 \\
      & Phi-3-mini    & 0.800 & 0.717 & \textbf{0.033} & 0.700 & 0.233 \\
    \midrule
    \multirow{2}{*}{GSM8K-v1 ($N{=}100$)}
      & Qwen~2.5-3B  & 0.970 & 0.970 & 0.980 & \textbf{0.210} & 0.060 \\
      & Phi-3-mini    & 0.340 & 0.450 & 0.320 & \textbf{0.130} & 0.160 \\
    \bottomrule
  \end{tabular}
\end{table}

