\begin{table}[h]
\centering
\caption{Commonsense format ablation (Qwen~2.5-3B-Instruct, $N{=}150$).
  Corrupting the answer-bearing final step collapses accuracy;
  corrupting the reasoning penultimate step does not.}
\label{tab:cs_ablation}
\begin{tabular}{lcc}
\toprule
Condition & Accuracy & $\Delta$ vs.\ full chain \\
\midrule
Full chain                         & \CSAFULL    & --- \\
Corrupt penultimate (reasoning)    & \CSACORRPEN & $-0.01$ \\
Neutral-stripped (last removed)    & \CSANEUTRAL & $-0.50$ \\
No conclusion (last deleted)       & \CSANOCONC  & $-0.47$ \\
Corrupt last (answer step)         & \CSACORRLAST & $-0.53$ \\
\bottomrule
\end{tabular}
\end{table}
